defmodule MyAppWeb.XmlController do
  use MyAppWeb, :controller

  def parse_xml(conn, %{"xml" => xml}) do
    case SweetXml.parse(xml) do
      {:ok, doc} ->
        xpath = xpath(doc)
        conn
        |> put_status(:created)
        |> render("parsed.xml", xpath: xpath)

      {:error, _} ->
        conn
        |> put_status(400)
        |> render("error.xml")
    end
  end

  defp xpath(doc) do
    doc
    |> SweetXml.xpath("/root/*")
    |> Enum.map(fn elem ->
      {elem.tag, elem.text}
    end)
  end
end